ts_lines.append("  content?: string; // Generated dynamically by seed system")
ts_lines.append("  summary: string;")
ts_lines.append("  categorySlug: string;")
ts_lines.append("  tags: string[];")
ts_lines.append("  applicableLaws: string[];")
ts_lines.append("  difficulty: 'GENERAL' | 'SPECIALIZED' | 'ADVANCED';")
