import hashlib
total = 0
for cat_slug, cat_data in categories.items():
    for title, difficulty, tags, laws in cat_data["contracts"]:
        # Generate slug from title
        slug_base = title.replace(" ", "-").replace("‌", "-").replace("\u200c", "")
        # Make slug ASCII-safe for uniqueness
        h = hashlib.md5(title.encode("utf-8")).hexdigest()[:8]
        slug = f"{cat_slug}-{h}"
        
        summary_map = {
            "GENERAL": "عمومی",
            "SPECIALIZED": "تخصصی",
            "ADVANCED": "پیشرفته"
        }
        summary = f"قرارداد {summary_map[difficulty]} {title} بر اساس قوانین موضوعه جمهوری اسلامی ایران"
        desc = f"{title} - قرارداد {summary_map[difficulty]} با شرایط و تعهدات مشخص"
        
        tags_str = json.dumps(tags, ensure_ascii=False)
        laws_str = json.dumps(laws, ensure_ascii=False)
        
        ts_lines.append("  {")
        ts_lines.append(f"    title: {json.dumps(title, ensure_ascii=False)},")
        ts_lines.append(f"    slug: '{slug}',")
        ts_lines.append(f"    description: {json.dumps(desc, ensure_ascii=False)},")
        ts_lines.append(f"    summary: {json.dumps(summary, ensure_ascii=False)},")
        ts_lines.append(f"    categorySlug: '{cat_slug}',")
        ts_lines.append(f"    tags: {tags_str},")
        ts_lines.append(f"    applicableLaws: {laws_str},")
        ts_lines.append(f"    difficulty: '{difficulty}',")
        ts_lines.append("  },")
        total += 1

ts_lines.append("];")

